const aiOutput = $input.first().json.output || '';

// Extract content between [CHARTS_JSON] and [/CHARTS_JSON]
const match = aiOutput.match(/\[CHARTS_JSON\]([\s\S]*?)\[\/CHARTS_JSON\]/);
if (!match) {
  return [{ json: { error: 'No CHARTS_JSON block found in AI output', rawOutput: aiOutput.slice(-800) } }];
}

// Strip markdown code fences if the AI wrapped the JSON in ```json ... ```
let raw = match[1].trim();
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();

let charts;
try {
  charts = JSON.parse(raw);
} catch (e) {
  // Attempt a light repair: remove trailing commas before ] or }
  const repaired = raw.replace(/,\s*([\]\}])/g, '$1');
  try {
    charts = JSON.parse(repaired);
  } catch (e2) {
    return [{ json: { error: 'Failed to parse CHARTS_JSON: ' + e2.message, rawJson: raw.slice(0, 800) } }];
  }
}

if (!Array.isArray(charts) || charts.length === 0) {
  return [{ json: { error: 'CHARTS_JSON is empty or not an array', raw: raw.slice(0, 400) } }];
}

// One output item per valid chart
return charts
  .filter(c => c && c.chartConfig && c.chartConfig.data)
  .map(c => ({ json: { sheetName: c.sheetName || 'chart', chartConfig: c.chartConfig } }));

// A Code node runs ONCE with all items — iterate with .map() to return all 5 charts
const allItems  = $input.all();
const allCharts = $('Parse AI Chart Configs').all();

return allItems.map((item, idx) => {
  const sheetName = allCharts[idx]?.json?.sheetName || ('chart_' + idx);
  return { json: { sheetName }, binary: item.binary };
});
